// src/components/Projects.js
import React from 'react';

const Projects = () => {
  return (
    <section className="projects">
      <h2>Projects</h2>
      <div className="project-list">
        <div className="project-item">
          <h3>Project 1</h3>
          <p>Empty</p>
          <a href="#">View Project</a>
        </div>
      </div>
    </section>
  );
};

export default Projects;
